/* Input Utils, By BlackStar, Ver.0.2.0 */
(()=>{"use strict";const repalceText=text=>text.toString().replace(/['".]/g,"").replace(/^[$_]/,"").trim();const getRadioBtnName=text=>"radiobutton-"+repalceText(text);const getListBoxName=text=>"listbox-"+repalceText(text);const addListeners=(entity,getName)=>{const parts=entity.args.raw.split(" ");$(document).on(":passagedisplay",(function(){for(const part of parts){const btnName=getName(part);$(`[name='${btnName}']`).change((()=>{const failRE=/^(?:do|for)$/;const passRE=/^(?:button|link(?:append|prepend|replace)?)$/;const closest=entity.contextFind((ctx=>failRE.test(ctx.name)||passRE.test(ctx.name)));if(closest&&failRE.test(closest.name)){return entity.error(`must not be used directly within macro <<${closest.name}>>`)}triggerEvent(":redo",document,{detail:{btnName:btnName}})}))}}))};Macro.add("redo_radio",{handler(){addListeners(this,getRadioBtnName)}});Macro.add("redo_list",{handler(){addListeners(this,getListBoxName)}})})();
/* End Input Utils */